module up_down_counter (
    input clk,
    input reset,
    input up_down,  // 1 for up, 0 for down
    output reg [3:0] q
);

    // Counter logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            q <= 4'b0000;
        else if (up_down)
            q <= q + 1;
        else
            q <= q - 1;
    end

endmodule
